// CF11 WF_NICHE_HEALTH — normalize triggers, scope projects, prepare per-project items.
// Triggers:
//   - Schedule (Sunday 03:00 UTC): no payload, scope = all active projects
//   - Webhook POST /webhook/niche-health/compute: optional { project_id, force }
// Output: one item per project to process. Global fetch + $env.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || {};
const projectIdFilter = payload.project_id || null;
const force = payload.force === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Compute prior Sunday (week_of) — Sunday just passed or today if run on Sunday UTC
const now = new Date();
const dow = now.getUTCDay();
const weekOf = new Date(now);
weekOf.setUTCDate(now.getUTCDate() - dow);
weekOf.setUTCHours(0, 0, 0, 0);
const weekOfDate = weekOf.toISOString().slice(0, 10);

// Load active, non-paused, non-archived projects (tolerate missing status column values)
let projUrl = `${supabaseUrl}/rest/v1/projects?select=id,niche,niche_description,niche_rpm_category,status,niche_health_score,niche_health_classification&or=(status.is.null,status.not.in.(paused,archived))`;
if (projectIdFilter) projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectIdFilter}&select=id,niche,niche_description,niche_rpm_category,status,niche_health_score,niche_health_classification`;

const pRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!pRes.ok) {
  throw new Error(`Fetch projects failed: HTTP ${pRes.status}: ${await pRes.text()}`);
}
const projects = await pRes.json();

if (!projects || projects.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: projectIdFilter ? `Project ${projectIdFilter} not found` : 'No active projects',
      via_webhook: viaWebhook,
      week_of: weekOfDate,
      http_status: 200
    }
  }];
}

// For each project, check idempotency (skip if niche_health_history row exists for this week_of and !force)
const items = [];
for (const proj of projects) {
  if (!force) {
    const idUrl = `${supabaseUrl}/rest/v1/niche_health_history?project_id=eq.${proj.id}&week_of=eq.${weekOfDate}&select=id&limit=1`;
    const idRes = await fetch(idUrl, { method: 'GET', headers: sbHeaders });
    if (idRes.ok) {
      const rows = await idRes.json();
      if (rows && rows.length > 0) {
        items.push({
          json: {
            project_id: proj.id,
            skipped: true,
            skip_reason: `Already computed for week ${weekOfDate}`,
            week_of: weekOfDate,
            via_webhook: viaWebhook
          }
        });
        continue;
      }
    }
  }
  items.push({
    json: {
      project_id: proj.id,
      niche: proj.niche,
      niche_description: proj.niche_description,
      niche_rpm_category: proj.niche_rpm_category,
      prior_score: proj.niche_health_score,
      prior_classification: proj.niche_health_classification,
      force,
      via_webhook: viaWebhook,
      week_of: weekOfDate,
      started_at: now.toISOString()
    }
  });
}

return items;

// CF11 per-project computation.
// Pulls 4-week competitor velocity + new channel entries + topic cluster freshness + rpm stability.
// Weighted 0-100 score: competitor_velocity (0-30) + new_channel_entry (0-20) + topic_freshness (0-25) + rpm_stability (0-25).
// Claude Haiku 4.5 produces insight_summary (one sentence, max 30 words).
// Inline exponential backoff for Claude. Inter-project batching (3) handled by n8n iteration.

const data = $input.item.json;
if (data.skipped) return $input.item;

const projectId = data.project_id;
const weekOfDate = data.week_of;
const runStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`${label} failed: HTTP ${res.status}: ${body.slice(0, 200)}`);
  }
  return res.json();
}

// Date windows
const nowMs = Date.now();
const fourWeeksAgo = new Date(nowMs - 28 * 86400000).toISOString();
const twelveWeeksAgo = new Date(nowMs - 84 * 86400000).toISOString();
const thirtyDaysAgo = new Date(nowMs - 30 * 86400000).toISOString();

try {
  // 1. Competitor videos last 4 weeks
  const recentVideos = await sbGet(
    `${supabaseUrl}/rest/v1/competitor_videos?project_id=eq.${projectId}&first_seen_at=gte.${encodeURIComponent(fourWeeksAgo)}&select=views_at_discovery,first_seen_at,title&limit=500`,
    'fetch recent competitor_videos'
  );

  // 2. Competitor videos prior 8 weeks (for velocity comparison)
  const priorVideos = await sbGet(
    `${supabaseUrl}/rest/v1/competitor_videos?project_id=eq.${projectId}&first_seen_at=gte.${encodeURIComponent(twelveWeeksAgo)}&first_seen_at=lt.${encodeURIComponent(fourWeeksAgo)}&select=views_at_discovery&limit=500`,
    'fetch prior competitor_videos'
  );

  // 3. New channel entries (tracked_since >= 30d ago)
  const newChannels = await sbGet(
    `${supabaseUrl}/rest/v1/competitor_channels?project_id=eq.${projectId}&is_active=eq.true&tracked_since=gte.${encodeURIComponent(thirtyDaysAgo)}&select=id`,
    'fetch new competitor_channels'
  );

  // 4. Project RPM stability — proxy: compare current niche_rpm_category to prior week_of history if exists
  let rpmStable = true;
  try {
    const priorWeek = new Date(new Date(weekOfDate).getTime() - 7 * 86400000).toISOString().slice(0, 10);
    const priorHist = await sbGet(
      `${supabaseUrl}/rest/v1/niche_health_history?project_id=eq.${projectId}&week_of=eq.${priorWeek}&select=score_breakdown&limit=1`,
      'fetch prior week history'
    );
    if (priorHist && priorHist[0] && priorHist[0].score_breakdown && priorHist[0].score_breakdown.rpm_category) {
      const prevCat = priorHist[0].score_breakdown.rpm_category;
      if (prevCat && data.niche_rpm_category && prevCat !== data.niche_rpm_category) rpmStable = false;
    }
  } catch (_) { /* non-fatal */ }

  // ───── Factor 1: competitor_velocity (0-30) ─────
  const avgRecent = recentVideos.length > 0 ? recentVideos.reduce((s, v) => s + (Number(v.views_at_discovery) || 0), 0) / recentVideos.length : 0;
  const avgPrior = priorVideos.length > 0 ? priorVideos.reduce((s, v) => s + (Number(v.views_at_discovery) || 0), 0) / priorVideos.length : 0;
  const velocityRatio = avgPrior > 0 ? (avgRecent / avgPrior) : (avgRecent > 0 ? 1.0 : 0);
  let competitor_velocity_score, velocity_trend;
  if (velocityRatio > 1.25) { competitor_velocity_score = 30; velocity_trend = 'rising'; }
  else if (velocityRatio >= 0.85) { competitor_velocity_score = 18; velocity_trend = 'stable'; }
  else { competitor_velocity_score = 5; velocity_trend = 'declining'; }

  // ───── Factor 2: new_channel_entry (0-20, inverse) ─────
  const newChannelCount = newChannels.length;
  let new_channel_entry_score;
  if (newChannelCount === 0) new_channel_entry_score = 20;
  else if (newChannelCount <= 3) new_channel_entry_score = 12;
  else if (newChannelCount <= 6) new_channel_entry_score = 6;
  else new_channel_entry_score = 0;
  const saturation_signal = newChannelCount >= 4;

  // ───── Factor 3: topic_freshness (0-25) via Claude Haiku cluster extraction ─────
  let topic_freshness_score = 0;
  let clusterCount = 0;
  let retryCountClaude = 0;
  let claudeCostUsd = 0;

  if (recentVideos.length > 0) {
    const titlesForClustering = recentVideos.slice(0, 80).map(v => (v.title || '').slice(0, 140)).filter(Boolean);
    const clusterPrompt = `You group YouTube video titles into topic clusters. Return JSON only.

TITLES (${titlesForClustering.length}):
${titlesForClustering.map((t, i) => `${i + 1}. ${t}`).join('\n')}

TASK: Identify distinct topic clusters by subject matter. Two videos are the same cluster if they cover substantially the same subject, not just similar aesthetics.

Return ONLY this JSON (no code fences):
{
  "distinct_cluster_count": 0,
  "clusters": [{"name": "...", "count": 0}]
}`;

    for (let attempt = 1; attempt <= 4; attempt++) {
      try {
        const res = await fetch('https://api.anthropic.com/v1/messages', {
          method: 'POST',
          headers: {
            'x-api-key': anthropicKey,
            'anthropic-version': '2023-06-01',
            'content-type': 'application/json'
          },
          body: JSON.stringify({
            model: 'claude-haiku-4-5-20251001',
            max_tokens: 700,
            messages: [{ role: 'user', content: clusterPrompt }]
          })
        });
        if (res.ok) {
          const body = await res.json();
          const txt = (body.content?.[0]?.text || '').replace(/```json|```/g, '').trim();
          let parsed = null;
          try { parsed = JSON.parse(txt); }
          catch { const m = txt.match(/\{[\s\S]*\}/); if (m) { try { parsed = JSON.parse(m[0]); } catch {} } }
          if (parsed && typeof parsed.distinct_cluster_count === 'number') {
            clusterCount = Math.max(0, Math.min(50, parsed.distinct_cluster_count));
          }
          claudeCostUsd = 0.002;
          break;
        }
        const errBody = await res.text();
        if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
      } catch (_) { }
      if (attempt < 4) {
        retryCountClaude += 1;
        await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
      }
    }

    // Fallback: if Claude failed, approximate cluster count from unique normalized first 3 words
    if (clusterCount === 0 && titlesForClustering.length > 0) {
      const groups = new Set();
      for (const t of titlesForClustering) {
        const norm = t.toLowerCase().replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
        groups.add(norm.split(' ').slice(0, 3).join(' '));
      }
      clusterCount = Math.min(50, groups.size);
    }
  }

  if (clusterCount >= 5) topic_freshness_score = 25;
  else if (clusterCount >= 3) topic_freshness_score = 15;
  else if (clusterCount >= 1) topic_freshness_score = 5;
  else topic_freshness_score = 0;

  // ───── Factor 4: rpm_stability (0-25) ─────
  const rpm_stability_score = rpmStable ? 25 : 10;

  // ───── Total score + classification ─────
  const health_score = Math.max(0, Math.min(100,
    competitor_velocity_score + new_channel_entry_score + topic_freshness_score + rpm_stability_score
  ));
  let classification;
  if (health_score >= 80) classification = 'thriving';
  else if (health_score >= 60) classification = 'stable';
  else if (health_score >= 40) classification = 'warning';
  else classification = 'critical';

  // Momentum trend — mirror competitor velocity
  const momentum_trend = velocity_trend;

  // ───── WoW delta ─────
  let week_over_week_delta = null;
  try {
    const priorWeekDate = new Date(new Date(weekOfDate).getTime() - 7 * 86400000).toISOString().slice(0, 10);
    const priorHist = await sbGet(
      `${supabaseUrl}/rest/v1/niche_health_history?project_id=eq.${projectId}&week_of=eq.${priorWeekDate}&select=health_score&limit=1`,
      'fetch prior week for delta'
    );
    if (priorHist && priorHist[0] && priorHist[0].health_score !== null && priorHist[0].health_score !== undefined) {
      week_over_week_delta = health_score - priorHist[0].health_score;
    }
  } catch (_) { /* non-fatal */ }

  // ───── Claude Haiku insight summary ─────
  const insightPrompt = `Given this niche's weekly health breakdown, write ONE sentence (max 30 words) summarizing the state + most actionable next step. Be blunt.

Classification: ${classification}
Score: ${health_score}/100 (WoW: ${week_over_week_delta === null ? 'n/a' : (week_over_week_delta >= 0 ? '+' : '') + week_over_week_delta})
Competitor velocity: ${competitor_velocity_score}/30 (${velocity_trend})
New channel entries: ${newChannelCount}
Topic clusters last 30d: ${clusterCount}
RPM category: ${data.niche_rpm_category || 'unset'} (stable: ${rpmStable})

Return only the sentence, no preamble.`;

  let insight_summary = null;
  for (let attempt = 1; attempt <= 4; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 150,
          messages: [{ role: 'user', content: insightPrompt }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        const txt = (body.content?.[0]?.text || '').trim();
        if (txt.length > 5) { insight_summary = txt.slice(0, 500); claudeCostUsd += 0.002; }
        break;
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (_) { }
    if (attempt < 4) {
      retryCountClaude += 1;
      await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
    }
  }
  if (!insight_summary) {
    // Deterministic fallback
    if (classification === 'thriving') insight_summary = `Niche thriving at ${health_score}/100 — publish aggressively; exploit topic freshness lead.`;
    else if (classification === 'stable') insight_summary = `Niche stable at ${health_score}/100 — maintain cadence; watch for saturation signals.`;
    else if (classification === 'warning') insight_summary = `Niche warning at ${health_score}/100 — tighten differentiation before competitors catch up.`;
    else insight_summary = `Niche critical at ${health_score}/100 — pause production; diversify or pivot angle.`;
  }

  // ───── Score breakdown JSON ─────
  const score_breakdown = {
    competitor_velocity: {
      score: competitor_velocity_score,
      max: 30,
      trend: velocity_trend,
      avg_views_recent: Math.round(avgRecent),
      avg_views_prior: Math.round(avgPrior),
      ratio: Math.round(velocityRatio * 1000) / 1000
    },
    new_channel_entry: {
      score: new_channel_entry_score,
      max: 20,
      new_channel_count: newChannelCount,
      saturation_signal
    },
    topic_freshness: {
      score: topic_freshness_score,
      max: 25,
      distinct_cluster_count: clusterCount
    },
    rpm_stability: {
      score: rpm_stability_score,
      max: 25,
      stable: rpmStable
    },
    rpm_category: data.niche_rpm_category || null
  };

  // ───── INSERT niche_health_history ─────
  const historyRow = {
    project_id: projectId,
    week_of: weekOfDate,
    health_score,
    classification,
    momentum_trend,
    saturation_signal,
    competitor_velocity_score,
    new_channel_entry_score,
    topic_freshness_score,
    rpm_stability_score,
    score_breakdown,
    week_over_week_delta,
    insight_summary,
    generated_by: 'claude-haiku-4-5-20251001'
  };

  let insertStatus = 'ok';
  try {
    const insRes = await fetch(`${supabaseUrl}/rest/v1/niche_health_history?on_conflict=project_id,week_of`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=minimal' },
      body: JSON.stringify(historyRow)
    });
    if (!insRes.ok) insertStatus = `history_insert HTTP ${insRes.status}`;
  } catch (e) { insertStatus = `history_insert threw: ${e.message}`; }

  // ───── PATCH projects ─────
  let patchStatus = 'ok';
  try {
    const pRes = await fetch(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        niche_health_score: health_score,
        niche_health_classification: classification,
        niche_health_last_computed_at: new Date().toISOString()
      })
    });
    if (!pRes.ok) patchStatus = `project_patch HTTP ${pRes.status}`;
  } catch (e) { patchStatus = `project_patch threw: ${e.message}`; }

  // ───── Alert if declining sharply or critical ─────
  let alertCreated = false;
  const shouldAlert = (week_over_week_delta !== null && week_over_week_delta <= -15) || health_score < 40;
  if (shouldAlert) {
    const severity = (health_score < 40 || (week_over_week_delta !== null && week_over_week_delta <= -25)) ? 'critical' : 'high';
    const deltaStr = week_over_week_delta === null ? '' : ` (WoW: ${week_over_week_delta >= 0 ? '+' : ''}${week_over_week_delta})`;
    try {
      const aRes = await fetch(`${supabaseUrl}/rest/v1/competitor_alerts`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          project_id: projectId,
          competitor_channel_id: null,
          competitor_video_id: null,
          alert_type: 'niche_health_decline',
          severity,
          title: `⚠️ Niche health ${classification} — ${health_score}/100${deltaStr}`,
          message: insight_summary,
          metadata: {
            reason: 'niche_health_decline',
            week_of: weekOfDate,
            health_score,
            classification,
            week_over_week_delta,
            score_breakdown
          }
        })
      });
      alertCreated = aRes.ok;
    } catch (_) { }
  }

  // production_logs
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'niche_health',
        scene_number: null,
        action: 'weekly_compute',
        status: (insertStatus === 'ok' && patchStatus === 'ok') ? 'success' : 'partial',
        duration_ms: Date.now() - runStart,
        cost_usd: claudeCostUsd,
        retry_count: retryCountClaude
      })
    });
  } catch (_) { }

  return {
    json: {
      project_id: projectId,
      week_of: weekOfDate,
      health_score,
      classification,
      momentum_trend,
      week_over_week_delta,
      score_breakdown,
      insight_summary,
      alert_created: alertCreated,
      insert_status: insertStatus,
      patch_status: patchStatus,
      cost_usd: claudeCostUsd,
      duration_ms: Date.now() - runStart,
      via_webhook: data.via_webhook
    }
  };
} catch (e) {
  // Project-level failure — log and continue
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'niche_health',
        scene_number: null,
        action: 'weekly_compute',
        status: 'error',
        duration_ms: Date.now() - runStart,
        cost_usd: 0,
        retry_count: 0
      })
    });
  } catch (_) { }
  return {
    json: {
      project_id: projectId,
      week_of: weekOfDate,
      error: e.message,
      via_webhook: data.via_webhook
    }
  };
}

// Aggregate across all projects processed this run.
const items = $input.all().map(i => i.json);
const meaningful = items.filter(j => !j.skipped);

if (meaningful.length === 0) {
  return [{
    json: {
      success: true,
      projects_processed: 0,
      projects_skipped: items.length,
      message: items[0]?.skip_reason || items[0]?.reason || 'Nothing to process',
      http_status: 200,
      via_webhook: items[0]?.via_webhook || false
    }
  }];
}

const classifications = { thriving: 0, stable: 0, warning: 0, critical: 0 };
let alerts = 0;
let errors = 0;
let totalCost = 0;
for (const m of meaningful) {
  if (m.error) { errors += 1; continue; }
  if (m.classification && classifications[m.classification] !== undefined) classifications[m.classification] += 1;
  if (m.alert_created) alerts += 1;
  totalCost += (m.cost_usd || 0);
}

return [{
  json: {
    success: true,
    projects_processed: meaningful.length,
    projects_skipped: items.length - meaningful.length,
    errors,
    alerts_created: alerts,
    classifications,
    total_cost_usd: Math.round(totalCost * 1000) / 1000,
    week_of: meaningful[0]?.week_of || null,
    per_project: meaningful.map(m => ({
      project_id: m.project_id,
      health_score: m.health_score,
      classification: m.classification,
      week_over_week_delta: m.week_over_week_delta,
      alert_created: m.alert_created || false,
      error: m.error || null
    })),
    finished_at: new Date().toISOString(),
    http_status: 200,
    via_webhook: meaningful.some(m => m.via_webhook)
  }
}];

// CF11 WF_NICHE_HEALTH — normalize triggers, scope projects, prepare per-project items.
// Triggers:
//   - Schedule (Sunday 03:00 UTC): no payload, scope = all active projects
//   - Webhook POST /webhook/niche-health/compute: optional { project_id, force }
// Output: one item per project to process. Global fetch + $env.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || {};
const projectIdFilter = payload.project_id || null;
const force = payload.force === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Compute prior Sunday (week_of) — Sunday just passed or today if run on Sunday UTC
const now = new Date();
const dow = now.getUTCDay();
const weekOf = new Date(now);
weekOf.setUTCDate(now.getUTCDate() - dow);
weekOf.setUTCHours(0, 0, 0, 0);
const weekOfDate = weekOf.toISOString().slice(0, 10);

// Load active, non-paused, non-archived projects (tolerate missing status column values)
let projUrl = `${supabaseUrl}/rest/v1/projects?select=id,niche,niche_description,niche_rpm_category,status,niche_health_score,niche_health_classification&or=(status.is.null,status.not.in.(paused,archived))`;
if (projectIdFilter) projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectIdFilter}&select=id,niche,niche_description,niche_rpm_category,status,niche_health_score,niche_health_classification`;

const pRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!pRes.ok) {
  throw new Error(`Fetch projects failed: HTTP ${pRes.status}: ${await pRes.text()}`);
}
const projects = await pRes.json();

if (!projects || projects.length === 0) {
  return [{
    json: {
      skipped: true,
      reason: projectIdFilter ? `Project ${projectIdFilter} not found` : 'No active projects',
      via_webhook: viaWebhook,
      week_of: weekOfDate,
      http_status: 200
    }
  }];
}

// For each project, check idempotency (skip if niche_health_history row exists for this week_of and !force)
const items = [];
for (const proj of projects) {
  if (!force) {
    const idUrl = `${supabaseUrl}/rest/v1/niche_health_history?project_id=eq.${proj.id}&week_of=eq.${weekOfDate}&select=id&limit=1`;
    const idRes = await fetch(idUrl, { method: 'GET', headers: sbHeaders });
    if (idRes.ok) {
      const rows = await idRes.json();
      if (rows && rows.length > 0) {
        items.push({
          json: {
            project_id: proj.id,
            skipped: true,
            skip_reason: `Already computed for week ${weekOfDate}`,
            week_of: weekOfDate,
            via_webhook: viaWebhook
          }
        });
        continue;
      }
    }
  }
  items.push({
    json: {
      project_id: proj.id,
      niche: proj.niche,
      niche_description: proj.niche_description,
      niche_rpm_category: proj.niche_rpm_category,
      prior_score: proj.niche_health_score,
      prior_classification: proj.niche_health_classification,
      force,
      via_webhook: viaWebhook,
      week_of: weekOfDate,
      started_at: now.toISOString()
    }
  });
}

return items;

// CF11 per-project computation.
// Pulls 4-week competitor velocity + new channel entries + topic cluster freshness + rpm stability.
// Weighted 0-100 score: competitor_velocity (0-30) + new_channel_entry (0-20) + topic_freshness (0-25) + rpm_stability (0-25).
// Claude Haiku 4.5 produces insight_summary (one sentence, max 30 words).
// Inline exponential backoff for Claude. Inter-project batching (3) handled by n8n iteration.

const data = $input.item.json;
if (data.skipped) return $input.item;

const projectId = data.project_id;
const weekOfDate = data.week_of;
const runStart = Date.now();

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) {
    const body = await res.text();
    throw new Error(`${label} failed: HTTP ${res.status}: ${body.slice(0, 200)}`);
  }
  return res.json();
}

// Date windows
const nowMs = Date.now();
const fourWeeksAgo = new Date(nowMs - 28 * 86400000).toISOString();
const twelveWeeksAgo = new Date(nowMs - 84 * 86400000).toISOString();
const thirtyDaysAgo = new Date(nowMs - 30 * 86400000).toISOString();

try {
  // 1. Competitor videos last 4 weeks
  const recentVideos = await sbGet(
    `${supabaseUrl}/rest/v1/competitor_videos?project_id=eq.${projectId}&first_seen_at=gte.${encodeURIComponent(fourWeeksAgo)}&select=views_at_discovery,first_seen_at,title&limit=500`,
    'fetch recent competitor_videos'
  );

  // 2. Competitor videos prior 8 weeks (for velocity comparison)
  const priorVideos = await sbGet(
    `${supabaseUrl}/rest/v1/competitor_videos?project_id=eq.${projectId}&first_seen_at=gte.${encodeURIComponent(twelveWeeksAgo)}&first_seen_at=lt.${encodeURIComponent(fourWeeksAgo)}&select=views_at_discovery&limit=500`,
    'fetch prior competitor_videos'
  );

  // 3. New channel entries (tracked_since >= 30d ago)
  const newChannels = await sbGet(
    `${supabaseUrl}/rest/v1/competitor_channels?project_id=eq.${projectId}&is_active=eq.true&tracked_since=gte.${encodeURIComponent(thirtyDaysAgo)}&select=id`,
    'fetch new competitor_channels'
  );

  // 4. Project RPM stability — proxy: compare current niche_rpm_category to prior week_of history if exists
  let rpmStable = true;
  try {
    const priorWeek = new Date(new Date(weekOfDate).getTime() - 7 * 86400000).toISOString().slice(0, 10);
    const priorHist = await sbGet(
      `${supabaseUrl}/rest/v1/niche_health_history?project_id=eq.${projectId}&week_of=eq.${priorWeek}&select=score_breakdown&limit=1`,
      'fetch prior week history'
    );
    if (priorHist && priorHist[0] && priorHist[0].score_breakdown && priorHist[0].score_breakdown.rpm_category) {
      const prevCat = priorHist[0].score_breakdown.rpm_category;
      if (prevCat && data.niche_rpm_category && prevCat !== data.niche_rpm_category) rpmStable = false;
    }
  } catch (_) { /* non-fatal */ }

  // ───── Factor 1: competitor_velocity (0-30) ─────
  const avgRecent = recentVideos.length > 0 ? recentVideos.reduce((s, v) => s + (Number(v.views_at_discovery) || 0), 0) / recentVideos.length : 0;
  const avgPrior = priorVideos.length > 0 ? priorVideos.reduce((s, v) => s + (Number(v.views_at_discovery) || 0), 0) / priorVideos.length : 0;
  const velocityRatio = avgPrior > 0 ? (avgRecent / avgPrior) : (avgRecent > 0 ? 1.0 : 0);
  let competitor_velocity_score, velocity_trend;
  if (velocityRatio > 1.25) { competitor_velocity_score = 30; velocity_trend = 'rising'; }
  else if (velocityRatio >= 0.85) { competitor_velocity_score = 18; velocity_trend = 'stable'; }
  else { competitor_velocity_score = 5; velocity_trend = 'declining'; }

  // ───── Factor 2: new_channel_entry (0-20, inverse) ─────
  const newChannelCount = newChannels.length;
  let new_channel_entry_score;
  if (newChannelCount === 0) new_channel_entry_score = 20;
  else if (newChannelCount <= 3) new_channel_entry_score = 12;
  else if (newChannelCount <= 6) new_channel_entry_score = 6;
  else new_channel_entry_score = 0;
  const saturation_signal = newChannelCount >= 4;

  // ───── Factor 3: topic_freshness (0-25) via Claude Haiku cluster extraction ─────
  let topic_freshness_score = 0;
  let clusterCount = 0;
  let retryCountClaude = 0;
  let claudeCostUsd = 0;

  if (recentVideos.length > 0) {
    const titlesForClustering = recentVideos.slice(0, 80).map(v => (v.title || '').slice(0, 140)).filter(Boolean);
    const clusterPrompt = `You group YouTube video titles into topic clusters. Return JSON only.

TITLES (${titlesForClustering.length}):
${titlesForClustering.map((t, i) => `${i + 1}. ${t}`).join('\n')}

TASK: Identify distinct topic clusters by subject matter. Two videos are the same cluster if they cover substantially the same subject, not just similar aesthetics.

Return ONLY this JSON (no code fences):
{
  "distinct_cluster_count": 0,
  "clusters": [{"name": "...", "count": 0}]
}`;

    for (let attempt = 1; attempt <= 4; attempt++) {
      try {
        const res = await fetch('https://api.anthropic.com/v1/messages', {
          method: 'POST',
          headers: {
            'x-api-key': anthropicKey,
            'anthropic-version': '2023-06-01',
            'content-type': 'application/json'
          },
          body: JSON.stringify({
            model: 'claude-haiku-4-5-20251001',
            max_tokens: 700,
            messages: [{ role: 'user', content: clusterPrompt }]
          })
        });
        if (res.ok) {
          const body = await res.json();
          const txt = (body.content?.[0]?.text || '').replace(/```json|```/g, '').trim();
          let parsed = null;
          try { parsed = JSON.parse(txt); }
          catch { const m = txt.match(/\{[\s\S]*\}/); if (m) { try { parsed = JSON.parse(m[0]); } catch {} } }
          if (parsed && typeof parsed.distinct_cluster_count === 'number') {
            clusterCount = Math.max(0, Math.min(50, parsed.distinct_cluster_count));
          }
          claudeCostUsd = 0.002;
          break;
        }
        const errBody = await res.text();
        if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
      } catch (_) { }
      if (attempt < 4) {
        retryCountClaude += 1;
        await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
      }
    }

    // Fallback: if Claude failed, approximate cluster count from unique normalized first 3 words
    if (clusterCount === 0 && titlesForClustering.length > 0) {
      const groups = new Set();
      for (const t of titlesForClustering) {
        const norm = t.toLowerCase().replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
        groups.add(norm.split(' ').slice(0, 3).join(' '));
      }
      clusterCount = Math.min(50, groups.size);
    }
  }

  if (clusterCount >= 5) topic_freshness_score = 25;
  else if (clusterCount >= 3) topic_freshness_score = 15;
  else if (clusterCount >= 1) topic_freshness_score = 5;
  else topic_freshness_score = 0;

  // ───── Factor 4: rpm_stability (0-25) ─────
  const rpm_stability_score = rpmStable ? 25 : 10;

  // ───── Total score + classification ─────
  const health_score = Math.max(0, Math.min(100,
    competitor_velocity_score + new_channel_entry_score + topic_freshness_score + rpm_stability_score
  ));
  let classification;
  if (health_score >= 80) classification = 'thriving';
  else if (health_score >= 60) classification = 'stable';
  else if (health_score >= 40) classification = 'warning';
  else classification = 'critical';

  // Momentum trend — mirror competitor velocity
  const momentum_trend = velocity_trend;

  // ───── WoW delta ─────
  let week_over_week_delta = null;
  try {
    const priorWeekDate = new Date(new Date(weekOfDate).getTime() - 7 * 86400000).toISOString().slice(0, 10);
    const priorHist = await sbGet(
      `${supabaseUrl}/rest/v1/niche_health_history?project_id=eq.${projectId}&week_of=eq.${priorWeekDate}&select=health_score&limit=1`,
      'fetch prior week for delta'
    );
    if (priorHist && priorHist[0] && priorHist[0].health_score !== null && priorHist[0].health_score !== undefined) {
      week_over_week_delta = health_score - priorHist[0].health_score;
    }
  } catch (_) { /* non-fatal */ }

  // ───── Claude Haiku insight summary ─────
  const insightPrompt = `Given this niche's weekly health breakdown, write ONE sentence (max 30 words) summarizing the state + most actionable next step. Be blunt.

Classification: ${classification}
Score: ${health_score}/100 (WoW: ${week_over_week_delta === null ? 'n/a' : (week_over_week_delta >= 0 ? '+' : '') + week_over_week_delta})
Competitor velocity: ${competitor_velocity_score}/30 (${velocity_trend})
New channel entries: ${newChannelCount}
Topic clusters last 30d: ${clusterCount}
RPM category: ${data.niche_rpm_category || 'unset'} (stable: ${rpmStable})

Return only the sentence, no preamble.`;

  let insight_summary = null;
  for (let attempt = 1; attempt <= 4; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 150,
          messages: [{ role: 'user', content: insightPrompt }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        const txt = (body.content?.[0]?.text || '').trim();
        if (txt.length > 5) { insight_summary = txt.slice(0, 500); claudeCostUsd += 0.002; }
        break;
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (_) { }
    if (attempt < 4) {
      retryCountClaude += 1;
      await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
    }
  }
  if (!insight_summary) {
    // Deterministic fallback
    if (classification === 'thriving') insight_summary = `Niche thriving at ${health_score}/100 — publish aggressively; exploit topic freshness lead.`;
    else if (classification === 'stable') insight_summary = `Niche stable at ${health_score}/100 — maintain cadence; watch for saturation signals.`;
    else if (classification === 'warning') insight_summary = `Niche warning at ${health_score}/100 — tighten differentiation before competitors catch up.`;
    else insight_summary = `Niche critical at ${health_score}/100 — pause production; diversify or pivot angle.`;
  }

  // ───── Score breakdown JSON ─────
  const score_breakdown = {
    competitor_velocity: {
      score: competitor_velocity_score,
      max: 30,
      trend: velocity_trend,
      avg_views_recent: Math.round(avgRecent),
      avg_views_prior: Math.round(avgPrior),
      ratio: Math.round(velocityRatio * 1000) / 1000
    },
    new_channel_entry: {
      score: new_channel_entry_score,
      max: 20,
      new_channel_count: newChannelCount,
      saturation_signal
    },
    topic_freshness: {
      score: topic_freshness_score,
      max: 25,
      distinct_cluster_count: clusterCount
    },
    rpm_stability: {
      score: rpm_stability_score,
      max: 25,
      stable: rpmStable
    },
    rpm_category: data.niche_rpm_category || null
  };

  // ───── INSERT niche_health_history ─────
  const historyRow = {
    project_id: projectId,
    week_of: weekOfDate,
    health_score,
    classification,
    momentum_trend,
    saturation_signal,
    competitor_velocity_score,
    new_channel_entry_score,
    topic_freshness_score,
    rpm_stability_score,
    score_breakdown,
    week_over_week_delta,
    insight_summary,
    generated_by: 'claude-haiku-4-5-20251001'
  };

  let insertStatus = 'ok';
  try {
    const insRes = await fetch(`${supabaseUrl}/rest/v1/niche_health_history?on_conflict=project_id,week_of`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'resolution=merge-duplicates,return=minimal' },
      body: JSON.stringify(historyRow)
    });
    if (!insRes.ok) insertStatus = `history_insert HTTP ${insRes.status}`;
  } catch (e) { insertStatus = `history_insert threw: ${e.message}`; }

  // ───── PATCH projects ─────
  let patchStatus = 'ok';
  try {
    const pRes = await fetch(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        niche_health_score: health_score,
        niche_health_classification: classification,
        niche_health_last_computed_at: new Date().toISOString()
      })
    });
    if (!pRes.ok) patchStatus = `project_patch HTTP ${pRes.status}`;
  } catch (e) { patchStatus = `project_patch threw: ${e.message}`; }

  // ───── Alert if declining sharply or critical ─────
  let alertCreated = false;
  const shouldAlert = (week_over_week_delta !== null && week_over_week_delta <= -15) || health_score < 40;
  if (shouldAlert) {
    const severity = (health_score < 40 || (week_over_week_delta !== null && week_over_week_delta <= -25)) ? 'critical' : 'high';
    const deltaStr = week_over_week_delta === null ? '' : ` (WoW: ${week_over_week_delta >= 0 ? '+' : ''}${week_over_week_delta})`;
    try {
      const aRes = await fetch(`${supabaseUrl}/rest/v1/competitor_alerts`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          project_id: projectId,
          competitor_channel_id: null,
          competitor_video_id: null,
          alert_type: 'niche_health_decline',
          severity,
          title: `⚠️ Niche health ${classification} — ${health_score}/100${deltaStr}`,
          message: insight_summary,
          metadata: {
            reason: 'niche_health_decline',
            week_of: weekOfDate,
            health_score,
            classification,
            week_over_week_delta,
            score_breakdown
          }
        })
      });
      alertCreated = aRes.ok;
    } catch (_) { }
  }

  // production_logs
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'niche_health',
        scene_number: null,
        action: 'weekly_compute',
        status: (insertStatus === 'ok' && patchStatus === 'ok') ? 'success' : 'partial',
        duration_ms: Date.now() - runStart,
        cost_usd: claudeCostUsd,
        retry_count: retryCountClaude
      })
    });
  } catch (_) { }

  return {
    json: {
      project_id: projectId,
      week_of: weekOfDate,
      health_score,
      classification,
      momentum_trend,
      week_over_week_delta,
      score_breakdown,
      insight_summary,
      alert_created: alertCreated,
      insert_status: insertStatus,
      patch_status: patchStatus,
      cost_usd: claudeCostUsd,
      duration_ms: Date.now() - runStart,
      via_webhook: data.via_webhook
    }
  };
} catch (e) {
  // Project-level failure — log and continue
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: null,
        stage: 'niche_health',
        scene_number: null,
        action: 'weekly_compute',
        status: 'error',
        duration_ms: Date.now() - runStart,
        cost_usd: 0,
        retry_count: 0
      })
    });
  } catch (_) { }
  return {
    json: {
      project_id: projectId,
      week_of: weekOfDate,
      error: e.message,
      via_webhook: data.via_webhook
    }
  };
}

// Aggregate across all projects processed this run.
const items = $input.all().map(i => i.json);
const meaningful = items.filter(j => !j.skipped);

if (meaningful.length === 0) {
  return [{
    json: {
      success: true,
      projects_processed: 0,
      projects_skipped: items.length,
      message: items[0]?.skip_reason || items[0]?.reason || 'Nothing to process',
      http_status: 200,
      via_webhook: items[0]?.via_webhook || false
    }
  }];
}

const classifications = { thriving: 0, stable: 0, warning: 0, critical: 0 };
let alerts = 0;
let errors = 0;
let totalCost = 0;
for (const m of meaningful) {
  if (m.error) { errors += 1; continue; }
  if (m.classification && classifications[m.classification] !== undefined) classifications[m.classification] += 1;
  if (m.alert_created) alerts += 1;
  totalCost += (m.cost_usd || 0);
}

return [{
  json: {
    success: true,
    projects_processed: meaningful.length,
    projects_skipped: items.length - meaningful.length,
    errors,
    alerts_created: alerts,
    classifications,
    total_cost_usd: Math.round(totalCost * 1000) / 1000,
    week_of: meaningful[0]?.week_of || null,
    per_project: meaningful.map(m => ({
      project_id: m.project_id,
      health_score: m.health_score,
      classification: m.classification,
      week_over_week_delta: m.week_over_week_delta,
      alert_created: m.alert_created || false,
      error: m.error || null
    })),
    finished_at: new Date().toISOString(),
    http_status: 200,
    via_webhook: meaningful.some(m => m.via_webhook)
  }
}];
